            {
                "stageId": "s2_post_call_hardening",
                "irPhase": "Post-Incident Activity",
                "prompt": "Attack was blocked (or succeeded). Help desk SOP was nearly bypassed by publicly-available information. CISO asks: what is the single technical control that makes voice impersonation impossible regardless of what information an attacker knows?",
                "analystContext": "Current verification methods: callback to corporate mobile (bypassable if caller claims device unavailable), employee ID (bypassable via LinkedIn). Goal: verification that cannot be researched, guessed, or socially engineered.",
                "options": [{"actionText": 'Suspend the targeted account temporarily and require in-person verification', "isCorrect": False, "consequence": 'Account suspended but no policy updated. Next vishing target for a different account succeeds because the helpdesk procedure is unchanged.', "nextStageId": None, "technicalExplanation": 'Individual account remediation without policy change leaves the rest of the organization vulnerable. Vishing is a process attack — the helpdesk procedure itself must be updated with callback verification for ALL sensitive requests.'}, {"actionText": "Disable the targeted user's account entirely until an investigation is complete", "isCorrect": False, "consequence": 'Account disabled without policy change. Next vishing call targets a different account. Helpdesk agent follows the same flawed procedure and complies.', "nextStageId": None, "technicalExplanation": 'Individual account remediation without updating the helpdesk callback verification procedure leaves every other account equally vulnerable. Vishing exploits process gaps — the process must change, not just the individual account status.'}, {"actionText": "Implement hardware FIDO2 security key verification for all help desk MFA resets: no reset occurs without the physical key. Add a 24-hour cooling period for all MFA re-enrollments.", "isCorrect": True, "consequence": "Physical FIDO2 verification is impossible to bypass via phone — attacker cannot produce a hardware token they don't possess. 24-hour cooldown prevents urgency-driven bypasses.", "nextStageId": None, "technicalExplanation": "FIDO2/WebAuthn keys are hardware-bound — they require physical possession, cannot be socially engineered, and cannot be transferred over a phone call. Alternative: require manager approval via SSO-authenticated Slack/Teams (identity verified by authenticated session, not by what they say). These controls defeat Scattered Spider's entire operational model."}, {"actionText": "Add a note to the affected user's file warning future helpdesk agents", "isCorrect": False, "consequence": 'Note is not checked by an agent 2 weeks later. Same attacker calls again with a different pretext and succeeds.', "nextStageId": None, "technicalExplanation": 'Manual notes in user files are not a reliable control — they depend on agents checking them for every call. A systematic control (callback verification policy, manager approval for sensitive resets, out-of-band verification) is required.'}]
            }
